import { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Menu, X, Home, Building2, Calculator, Phone, LogIn, User, LogOut } from 'lucide-react';

const Navbar = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout, isAuthenticated } = useAuth();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const navLinks = [
    { name: 'Home', path: '/', icon: Home },
    { name: 'Properties', path: '/projects', icon: Building2 },
    { name: 'EMI Calculator', path: '/emi-calculator', icon: Calculator },
    { name: 'Contact', path: '/contact', icon: Phone },
  ];

  return (
    <nav className="bg-[#0a192f] py-4 fixed top-0 w-full z-50 shadow-lg">
      <div className="container-custom">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2">
            <div className="w-10 h-10 bg-[#c6a43b] rounded-lg flex items-center justify-center">
              <span className="text-[#0a192f] font-bold text-xl">S</span>
            </div>
            <div>
              <span className="text-white font-bold text-xl tracking-wide">SWABHAGYA</span>
              <span className="text-[#c6a43b] font-bold text-xl"> REALTY</span>
            </div>
          </Link>
          
          {/* Desktop Menu */}
          <div className="hidden md:flex items-center gap-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`flex items-center gap-2 transition-all duration-300 font-medium ${
                  location.pathname === link.path 
                    ? 'text-[#c6a43b]' 
                    : 'text-white/80 hover:text-[#c6a43b]'
                }`}
              >
                <link.icon size={18} />
                {link.name}
              </Link>
            ))}
            
            {isAuthenticated ? (
              <div className="relative group">
                <button className="flex items-center gap-2 bg-[#c6a43b]/10 px-4 py-2 rounded-lg text-white hover:bg-[#c6a43b]/20 transition">
                  <User size={18} />
                  <span>{user?.name?.split(' ')[0]}</span>
                </button>
                <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-xl hidden group-hover:block">
                  <Link to="/dashboard" className="flex items-center gap-2 px-4 py-2 text-gray-700 hover:bg-gray-100">
                    <User size={16} /> Dashboard
                  </Link>
                  <button
                    onClick={handleLogout}
                    className="flex items-center gap-2 w-full text-left px-4 py-2 text-gray-700 hover:bg-gray-100"
                  >
                    <LogOut size={16} /> Logout
                  </button>
                </div>
              </div>
            ) : (
              <Link
                to="/login"
                className="flex items-center gap-2 bg-[#c6a43b] text-[#0a192f] px-5 py-2 rounded-lg hover:bg-opacity-90 transition font-semibold"
              >
                <LogIn size={18} />
                Login / Signup
              </Link>
            )}
          </div>
          
          {/* Mobile Menu Button */}
          <button 
            className="md:hidden text-white"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
        
        {/* Mobile Menu */}
        {isMobileMenuOpen && (
          <div className="md:hidden mt-4 bg-[#0a192f] rounded-lg p-4 border border-[#c6a43b]/20">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c6a43b] transition"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                <link.icon size={18} />
                {link.name}
              </Link>
            ))}
            <div className="border-t border-white/20 pt-3 mt-2">
              {isAuthenticated ? (
                <>
                  <Link to="/dashboard" className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c6a43b]">
                    <User size={18} /> Dashboard
                  </Link>
                  <button onClick={handleLogout} className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c6a43b] w-full">
                    <LogOut size={18} /> Logout
                  </button>
                </>
              ) : (
                <Link to="/login" className="flex items-center gap-3 py-3 text-[#c6a43b] font-semibold">
                  <LogIn size={18} /> Login / Signup
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
